import{_ as i,o as a,c as e,a as n}from"./chunks/framework.8tiMeCK-.js";const c=JSON.parse('{"title":"7.4  精准打击：用 objdump 和 GDB 定位罪魁祸首","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch07_4.md","filePath":"notes/linux_kernel_debugging/ch07_4.md","lastUpdated":null}'),p={name:"notes/linux_kernel_debugging/ch07_4.md"};function l(t,s,h,d,k,r){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="_7-4-精准打击-用-objdump-和-gdb-定位罪魁祸首" tabindex="-1">7.4 精准打击：用 objdump 和 GDB 定位罪魁祸首 <a class="header-anchor" href="#_7-4-精准打击-用-objdump-和-gdb-定位罪魁祸首" aria-label="Permalink to &quot;7.4  精准打击：用 objdump 和 GDB 定位罪魁祸首&quot;">​</a></h1><p>上一节我们把尸检报告读完了。我们知道了 <code>do_the_work</code> 函数挂了，也知道 RIP 寄存器停在了偏移量 <code>0x124</code> 的地方。</p><p>但这还不够。</p><p>问题是「精准定位」。我们想知道究竟是源代码的第几行、哪个语句导致了这场灾难。是那个 <code>pr_info</code> 吗？还是后面那句赋值？</p><p>这就需要把 RIP 地址（或者偏移量）反向映射到源代码行。这就是本节要做的事：从「大概知道」到「确切知道」。</p><hr><h2 id="调试前的准备-给内核装上窃听器" tabindex="-1">调试前的准备：给内核装上窃听器 <a class="header-anchor" href="#调试前的准备-给内核装上窃听器" aria-label="Permalink to &quot;调试前的准备：给内核装上窃听器&quot;">​</a></h2><p>在开始实战之前，有一个先决条件：<strong>你的二进制文件里必须有调试符号</strong>。</p><p>没有符号的二进制文件就像去了标签的药瓶——你只知道里面有药，但不知道哪颗是止疼药，哪颗是毒药。</p><p>要获得最完整的调试体验，你必须用 <code>CONFIG_DEBUG_INFO=y</code> 重新编译你的 buggy 内核或模块。简单来说，就是在调试内核上启动，并在那里构建你的模块。</p><p>打开我们所谓的「加强版 Makefile」，找到这个变量：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MYDEBUG := y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它默认是 <code>n</code>，你需要把它改成 <code>y</code>。</p><p>重新构建模块。你会注意到，生成的 <code>.ko</code> 文件变大了——有时候是大得多了。这很正常，因为它现在不仅包含机器码，还包含了一份详尽的「地图」，告诉调试器哪段机器码对应哪一行 C 代码。</p><hr><h2 id="objdump-反汇编界的显微镜" tabindex="-1">objdump：反汇编界的显微镜 <a class="header-anchor" href="#objdump-反汇编界的显微镜" aria-label="Permalink to &quot;objdump：反汇编界的显微镜&quot;">​</a></h2><p><code>objdump</code> 是个强力工具，它能把 ELF 目标文件（包括未压缩的内核镜像 <code>vmlinux</code> 和模块 <code>.ko</code> 文件）拆得七零八落，让你看清里面的每一根血管。</p><p>最常用的组合拳是 <code>-dS</code> 选项：</p><ul><li><code>-d</code> (--disassemble)：反汇编可执行段。</li><li><code>-S</code> (--source)：尽可能把源代码插在汇编里面显示（前提是你用 <code>-g</code> 编译过）。</li></ul><h3 id="第一步-找到模块在内存里的家址" tabindex="-1">第一步：找到模块在内存里的家址 <a class="header-anchor" href="#第一步-找到模块在内存里的家址" aria-label="Permalink to &quot;第一步：找到模块在内存里的家址&quot;">​</a></h3><p>如果你的模块还在内存里跑着（或刚挂掉），你可以先从 <code>/proc/modules</code> 里抓到它的加载基址。</p><p>普通用户看这个文件时，内核为了安全（防止信息泄露），会把地址藏起来：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> oops_tryv2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/modules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">oops_tryv2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16384</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Live</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x0000000000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (OE)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>全是零。这没用。</p><p>你需要 root 权限来窥探真相：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> oops_tryv2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/modules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">oops_tryv2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16384</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Live</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0xffffffffc0604000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (OE)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看到了吗？<code>0xffffffffc0604000</code>。这就是我们的模块被加载到的内核虚拟地址（VMA）。</p><h3 id="第二步-生成带地址的反汇编文件" tabindex="-1">第二步：生成带地址的反汇编文件 <a class="header-anchor" href="#第二步-生成带地址的反汇编文件" aria-label="Permalink to &quot;第二步：生成带地址的反汇编文件&quot;">​</a></h3><p>有了基址，我们就可以让 <code>objdump</code> 动手了。关键在于 <code>--adjust-vma</code> 参数，它告诉 objdump：「请假装这个模块是从这个地址开始的」，这样输出的左侧地址就会和真实运行时的内核地址一一对应。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --adjust-vma=0xffffffffc0604000</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_tryv2.ko</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> oops_tryv2.disas</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>打开生成的 <code>oops_tryv2.disas</code>，你会看到类似这样的输出：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">static void do_the_work(struct work_struct *work)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffffffffc0604000:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	e8 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 00</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 00</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 	callq  ffffffffc0604005 &lt;do_the_work+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffffffffc0604005:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	55</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                   	push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rbp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>左侧是绝对地址，中间是机器码，右边是汇编和夹杂的 C 源码。</p><h3 id="第三步-算出精确的死亡地址" tabindex="-1">第三步：算出精确的死亡地址 <a class="header-anchor" href="#第三步-算出精确的死亡地址" aria-label="Permalink to &quot;第三步：算出精确的死亡地址&quot;">​</a></h3><p>还记得上一节我们从 Oops 消息里抠出来的 RIP 值吗？</p><p><code>RIP: 0033:[&lt;ffffffffc0604124&gt;]</code></p><p>这是一个绝对地址。但因为我们在 objdump 里已经指定了模块基址，或者更简单点，我们直接用 Oops 消息里提示的<strong>偏移量</strong>——也就是 <code>&lt;do_the_work+0x124&gt;</code> 里的 <code>0x124</code>。</p><p>计算公式非常简单：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模块基址 (从 /proc/modules 来) + 偏移量 (从 Oops RIP 来) = 精确崩溃地址</span></span>
<span class="line"><span>0xffffffffc0604000 + 0x124 = 0xffffffffc0604124</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="第四步-按图索骥" tabindex="-1">第四步：按图索骥 <a class="header-anchor" href="#第四步-按图索骥" aria-label="Permalink to &quot;第四步：按图索骥&quot;">​</a></h3><p>拿着计算出来的 <code>0xffffffffc0604124</code>，在刚才生成的 <code>oops_tryv2.disas</code> 文件里搜。</p><p>你会找到这一段（请盯着左边的地址看）：</p><p><em>(此处对应原图 7.15/7.16，展示 objdump 输出)</em></p><p>在那一堆十六进制代码里，你会发现 <code>0xffffffffc0604124</code> 这一行的上方，正是那行罪魁祸首的 C 代码：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">61</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">              pr_info</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Generating Oops by attempting to write to an invalid kernel memory pointer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">62</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              oopsie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;x&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>找到了。<strong>就是第 62 行</strong>。</p><p>通过这个方法，我们把 RIP 寄存器里的冷冰冰的数字，变成了具体的一行 C 代码。这比瞎猜要快一万倍。</p><p>⚠️ <strong>注意</strong> 如果你不是在现网（live run）调试，也就是说手头没有 <code>/proc/modules</code> 的基址，直接用 objdump 也可以，只是不要加 <code>--adjust-vma</code> 参数。这时你需要手动把 Oops 里的偏移量（如 <code>0x124</code>）跟 objdump 输出里的相对地址对应起来。原理一模一样。</p><h3 id="题外话-如果是内核本身崩了" tabindex="-1">题外话：如果是内核本身崩了？ <a class="header-anchor" href="#题外话-如果是内核本身崩了" aria-label="Permalink to &quot;题外话：如果是内核本身崩了？&quot;">​</a></h3><p>如果罪魁祸首不是模块，而是内核核心代码，方法也一样。只不过输入文件换成了未压缩的 <code>vmlinux</code> 镜像：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\${CROSS_COMPILE}objdump -dS </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path/to/kernel-src/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/vmlinux </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vmlinux.disas</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>当然，前提是你的 <code>vmlinux</code> 是带着调试信息编译的。这是一劳永逸的事——除非你更新了内核，否则这份反汇编文件可以一直用。</p><hr><h2 id="gdb-不用反汇编文件也能查" tabindex="-1">GDB：不用反汇编文件也能查 <a class="header-anchor" href="#gdb-不用反汇编文件也能查" aria-label="Permalink to &quot;GDB：不用反汇编文件也能查&quot;">​</a></h2><p>如果你觉得手算地址或者 grep 反汇编文件太麻烦，GDB 提供了一种更「自动化」的查询方式。</p><p>前提还是一样：你的模块得带着调试符号编（也就是前面 Makefile 里的 <code>MYDEBUG := y</code>）。</p><p>为了方便 GDB 调试，我们的 Makefile 在开启 <code>MYDEBUG</code> 时，其实悄悄加上了一堆编译选项：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ccflags-y += -DDEBUG -g -ggdb -gdwarf-4 -Og -Wall -fno-omit-frame-pointer -fvar-tracking-assignments</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><em>（<code>-g</code> 是关键，<code>-Og</code> 是为了优化但不至于乱序太严重，方便调试）</em></p><p>把 GDB 指向你的 <code>.ko</code> 文件（注意，这里是 <code>.ko</code>，不是 <code>.o</code>）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_tryv2.ko</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Reading</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> symbols</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_tryv2.ko...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">do_the_work+0x124</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>注意这个语法：<code>list *函数名+偏移量</code>。这里 <code>0x124</code> 就是我们从 Oops 消息里拿到的 RIP 偏移。</p><p>GDB 会立刻吐出这一段：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">160</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> is in </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">do_the_work</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ch7</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">oops_tryv2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">oops_tryv2.c:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">62</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  [...]</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">61</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">              pr_info</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Generating Oops by attempting to write to an invalid kernel memory pointer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">62</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              oopsie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;x&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">63</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">         }</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         kfree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(gctx);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(gdb)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>完美命中。又是第 62 行。</p><p>GDB 的好处是它懂文件格式（ELF）和调试信息（DWARF），不用你自己去算十六进制加减法。只要你给它正确的模块文件和偏移量，它就能把你带到案发现场。</p><hr><h2 id="addr2line-简单粗暴的地址转换器" tabindex="-1">addr2line：简单粗暴的地址转换器 <a class="header-anchor" href="#addr2line-简单粗暴的地址转换器" aria-label="Permalink to &quot;addr2line：简单粗暴的地址转换器&quot;">​</a></h2><p>如果你觉得 GDB 太重，或者你只想写个脚本来批量处理地址，<code>addr2line</code> 是个更轻量的选择。</p><p>顾名思义，它的功能就是：<strong>地址 -&gt; 文件:行号</strong>。</p><p>用法很直接。你得给它指定可执行文件（<code>-e</code>），然后给它一个地址（或者多个）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr2line</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_tryv2.o</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x124</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><em>注意：这里 addr2line 通常用在 <code>.o</code> 文件或者带符号的 ELF 上，有时 <code>.ko</code> 也可以，取决于符号是否被 strip。如果 <code>.ko</code> 不行，试试构建中间生成的 <code>.o</code> 文件。</em></p><p>输出：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>do_the_work at &lt;...&gt;/ch7/oops_tryv2/oops_tryv2.c:62</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>参数解释：</p><ul><li><code>-e</code>：指定二进制文件。</li><li><code>-f</code>：显示函数名。</li><li><code>-p</code>：美化输出格式，让它更易读。</li></ul><p>依然是第 62 行。工具换了，真相只有一个。</p><p>如果是内核崩溃，手里拿着 <code>vmlinux</code> 和一个内核虚拟地址，用法也是一样的：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">addr2line</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">vmlinux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">faulting_kernel_addres</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>⚠️ <strong>注意：KASLR 的坑</strong> 这里有个历史遗留问题。如果你的系统开启了 KASLR（内核地址空间布局随机化，Kernel Address Space Layout Randomization），也就是那个为了安全让内核基址每次启动都随机的特性，那么 <code>addr2line</code> 就瞎了。</p><p>为什么？因为 Oops 里的地址是「随机化后的绝对地址」，而 <code>vmlinux</code> 里的符号是「编译时的相对地址」。<code>addr2line</code> 不知道这次启动的随机偏移量是多少。</p><p>遇到这种情况，你有两个选择：</p><ol><li><strong>关掉 KASLR</strong>：启动参数加 <code>nokaslr</code>。</li><li><strong>用 <code>faddr2line</code></strong>：这是专门为对付 KASLR 设计的脚本，我们下一节会讲到。</li></ol><hr><p>到这里，我们已经把定位 Oops 位置的三板斧——objdump、GDB、addr2line——都过了一遍。掌握了这些，你就再也不用对着 Oops 里的十六进制地址干瞪眼了。</p>`,86)])])}const g=i(p,[["render",l]]);export{c as __pageData,g as default};
